import{f as E,D as u,o as d,c as A,a2 as n,b as s,w as o,a,G as l,a5 as i,k as r}from"./chunks/framework.DHYrF-q6.js";const k=JSON.parse('{"title":"AI 技术基础","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/tech-basics.md","filePath":"ai-product-manager/tech-basics.md","lastUpdated":1781090728000}'),h={name:"ai-product-manager/tech-basics.md"};function q(B,t,p,m,g,b){const e=u("Mermaid");return d(),A("div",null,[t[3]||(t[3]=n('<h1 id="ai-技术基础" tabindex="-1">AI 技术基础 <a class="header-anchor" href="#ai-技术基础" aria-label="Permalink to &quot;AI 技术基础&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>AI 产品经理不需要编写复杂算法，但<strong>必须能够准确评估技术边界</strong>——这是与传统 PM 最本质的差异之一。本章从机器学习核心概念、深度学习入门、大模型原理、MLOps 工程四个维度，构建&quot;够用且够深&quot;的技术认知。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>能判断&quot;这个需求用现有技术能不能做&quot;、&quot;大概多长时间能做出来&quot;、&quot;成本大概多少&quot;，并能跟算法团队进行有深度的技术沟通。</p></div><hr><h2 id="一、知识图谱" tabindex="-1">一、知识图谱 <a class="header-anchor" href="#一、知识图谱" aria-label="Permalink to &quot;一、知识图谱&quot;">​</a></h2>',6)),(d(),s(i,null,{default:o(()=>[l(e,{id:"mermaid-18",class:"mermaid",graph:"mindmap%0A%20%20root((AI%20%E6%8A%80%E6%9C%AF%E5%9F%BA%E7%A1%80))%0A%20%20%20%20%E6%9C%BA%E5%99%A8%E5%AD%A6%E4%B9%A0%E6%A0%B8%E5%BF%83%0A%20%20%20%20%20%20%E7%9B%91%E7%9D%A3%20vs%20%E6%97%A0%E7%9B%91%E7%9D%A3%20vs%20%E5%BC%BA%E5%8C%96%0A%20%20%20%20%20%20%E5%88%86%E7%B1%BB%20%2F%20%E5%9B%9E%E5%BD%92%20%2F%20%E8%81%9A%E7%B1%BB%0A%20%20%20%20%20%20%E8%AF%84%E4%BC%B0%E6%8C%87%E6%A0%87%0A%20%20%20%20%20%20%E8%BF%87%E6%8B%9F%E5%90%88%E4%B8%8E%E6%AC%A0%E6%8B%9F%E5%90%88%0A%20%20%20%20%E6%B7%B1%E5%BA%A6%E5%AD%A6%E4%B9%A0%E5%85%A5%E9%97%A8%0A%20%20%20%20%20%20%E7%A5%9E%E7%BB%8F%E7%BD%91%E7%BB%9C%E5%9F%BA%E7%A1%80%0A%20%20%20%20%20%20CNN%20%2F%20RNN%20%2F%20Transformer%0A%20%20%20%20%20%20%E6%8D%9F%E5%A4%B1%E5%87%BD%E6%95%B0%E4%B8%8E%E4%BC%98%E5%8C%96%E5%99%A8%0A%20%20%20%20%20%20%E5%8F%8D%E5%90%91%E4%BC%A0%E6%92%AD%0A%20%20%20%20%E5%A4%A7%E6%A8%A1%E5%9E%8B%E5%8E%9F%E7%90%86%0A%20%20%20%20%20%20Token%20%E4%B8%8E%20Tokenization%0A%20%20%20%20%20%20Embedding%20%E8%AF%AD%E4%B9%89%E5%90%91%E9%87%8F%0A%20%20%20%20%20%20Attention%20%E6%B3%A8%E6%84%8F%E5%8A%9B%E6%9C%BA%E5%88%B6%0A%20%20%20%20%20%20Transformer%20%E6%9E%B6%E6%9E%84%0A%20%20%20%20%20%20Decoder-only%20%E6%A8%A1%E5%9E%8B%0A%20%20%20%20MLOps%20%E5%B7%A5%E7%A8%8B%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E7%89%88%E6%9C%AC%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E8%AE%AD%E7%BB%83%E6%B5%81%E7%A8%8B%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E9%83%A8%E7%BD%B2%E4%B8%8E%E6%9C%8D%E5%8A%A1%0A%20%20%20%20%20%20%E7%9B%91%E6%8E%A7%E4%B8%8E%E6%BC%82%E7%A7%BB%E6%A3%80%E6%B5%8B%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[a(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r("hr",null,null,-1)),t[5]||(t[5]=r("h2",{id:"二、机器学习核心概念",tabindex:"-1"},[a("二、机器学习核心概念 "),r("a",{class:"header-anchor",href:"#二、机器学习核心概念","aria-label":'Permalink to "二、机器学习核心概念"'},"​")],-1)),t[6]||(t[6]=r("h3",{id:"_2-1-三大学习范式",tabindex:"-1"},[a("2.1 三大学习范式 "),r("a",{class:"header-anchor",href:"#_2-1-三大学习范式","aria-label":'Permalink to "2.1 三大学习范式"'},"​")],-1)),(d(),s(i,null,{default:o(()=>[l(e,{id:"mermaid-26",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%E7%9B%91%E7%9D%A3%E5%AD%A6%E4%B9%A0%0A%20%20%20%20A1%5B%E5%B8%A6%E6%A0%87%E7%AD%BE%E6%95%B0%E6%8D%AE%5D%20--%3E%20A2%5B%E8%AE%AD%E7%BB%83%E6%A8%A1%E5%9E%8B%5D%20--%3E%20A3%5B%E9%A2%84%E6%B5%8B%E6%A0%87%E7%AD%BE%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E6%97%A0%E7%9B%91%E7%9D%A3%E5%AD%A6%E4%B9%A0%0A%20%20%20%20B1%5B%E6%97%A0%E6%A0%87%E7%AD%BE%E6%95%B0%E6%8D%AE%5D%20--%3E%20B2%5B%E5%8F%91%E7%8E%B0%E6%A8%A1%E5%BC%8F%5D%20--%3E%20B3%5B%E8%81%9A%E7%B1%BB%2F%E9%99%8D%E7%BB%B4%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%BC%BA%E5%8C%96%E5%AD%A6%E4%B9%A0%0A%20%20%20%20C1%5B%E7%8E%AF%E5%A2%83%E4%BA%A4%E4%BA%92%5D%20--%3E%20C2%5B%E8%AF%95%E9%94%99%E5%AD%A6%E4%B9%A0%5D%20--%3E%20C3%5B%E6%9C%80%E5%A4%A7%E5%8C%96%E5%A5%96%E5%8A%B1%5D%0A%20%20%20%20end%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[a(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=n('<table tabindex="0"><thead><tr><th>范式</th><th>核心思路</th><th>典型场景</th><th>PM 需要知道的</th></tr></thead><tbody><tr><td><strong>监督学习</strong></td><td>给数据打标签，让模型学习&quot;输入→输出&quot;的映射</td><td>垃圾邮件分类、图像识别、信用评分</td><td>标注成本是最大的隐性成本</td></tr><tr><td><strong>无监督学习</strong></td><td>不给标签，让模型自己发现数据中的结构</td><td>用户分群、异常检测、推荐系统</td><td>聚类结果需要业务解读，不是纯技术输出</td></tr><tr><td><strong>强化学习</strong></td><td>从环境反馈中学习最优策略</td><td>游戏 AI、机器人控制、A/B 自动化</td><td>落地难度最高，周期最长，慎用</td></tr></tbody></table><h3 id="_2-2-分类-vs-回归" tabindex="-1">2.2 分类 vs 回归 <a class="header-anchor" href="#_2-2-分类-vs-回归" aria-label="Permalink to &quot;2.2 分类 vs 回归&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">面试追问</p><p><strong>Q: 分类和回归的区别是什么？各给一个实际产品中的例子。</strong></p><p><strong>A:</strong> 分类是预测&quot;类别&quot;（离散值），回归是预测&quot;数值&quot;（连续值）。</p><ul><li>分类案例：电商评价情感分析——输入评论文本，输出&quot;正面/中性/负面&quot;。产品设计中要考虑的是：分类错误的代价不对称——把负面判成正面比正面判成负面更严重（可能漏掉投诉）。</li><li>回归案例：外卖配送时间预估——输入订单信息、骑手位置、天气等，输出预计配送分钟数。产品设计中要考虑的是：大部分用户宁可早到 5 分钟也不要晚到 1 分钟，所以回归模型的重点是控制低估（Under-estimation）的比例。</li></ul></div><h3 id="_2-3-评估指标——只看准确率是不够的" tabindex="-1">2.3 评估指标——只看准确率是不够的 <a class="header-anchor" href="#_2-3-评估指标——只看准确率是不够的" aria-label="Permalink to &quot;2.3 评估指标——只看准确率是不够的&quot;">​</a></h3><p>在实际产品中，准确率只是最粗糙的指标。你需要根据场景选择更细粒度的评估维度：</p><table tabindex="0"><thead><tr><th>指标</th><th>公式含义</th><th>适用场景</th><th>PM 视角</th></tr></thead><tbody><tr><td><strong>准确率 Accuracy</strong></td><td>预测正确的比例</td><td>类别均衡的场景</td><td>92% 准确率在反欺诈场景是灾难——因为 99% 的交易都是正常的</td></tr><tr><td><strong>精确率 Precision</strong></td><td>预测为正例中真正为正例的比例</td><td>误报代价高的场景（垃圾邮件过滤）</td><td>&quot;宁漏杀不误杀&quot;</td></tr><tr><td><strong>召回率 Recall</strong></td><td>真正的正例中被正确识别出来的比例</td><td>漏报代价高的场景（癌症筛查）</td><td>&quot;宁可错杀不能放过&quot;</td></tr><tr><td><strong>F1 Score</strong></td><td>精确率和召回率的调和平均</td><td>精确率和召回率都需要平衡</td><td>要跟业务方讨论&quot;哪个方向更不可接受&quot;</td></tr><tr><td><strong>AUC</strong></td><td>分类器区分正负样本的能力</td><td>二分类场景的综合评估</td><td>AUC 0.85 和 0.88 在业务上可能没区别</td></tr></tbody></table><details class="details custom-block"><summary>实战案例：为什么准确率在反欺诈场景是&quot;假指标&quot;？</summary><p>我们之前的风控模型评估时，准确率是 98.5%——看起来很好对吧？问题在于，交易数据中 99% 的样本都是正常交易。模型只要&quot;全部判为正常&quot;，准确率就是 99%。但这个模型在欺诈交易上的召回率是 0%——一条欺诈都没抓到。</p><p>所以我们把评估重点换成了&quot;欺诈交易的召回率 + 正常交易的误判率&quot;：召回率目标 90% 以上，误判率控制在 3% 以下。误判率 3% 意味着 100 个正常用户里有 3 个会被拦截——这对用户体验的影响需要产品层面来权衡，不是纯技术问题。</p></details><h3 id="_2-4-过拟合与欠拟合——ai-pm-必须理解的概念" tabindex="-1">2.4 过拟合与欠拟合——AI PM 必须理解的概念 <a class="header-anchor" href="#_2-4-过拟合与欠拟合——ai-pm-必须理解的概念" aria-label="Permalink to &quot;2.4 过拟合与欠拟合——AI PM 必须理解的概念&quot;">​</a></h3><table tabindex="0"><thead><tr><th>现象</th><th>训练集表现</th><th>测试集表现</th><th>产品表现</th><th>应对方案</th></tr></thead><tbody><tr><td><strong>欠拟合</strong></td><td>差</td><td>差</td><td>模型太&quot;简单&quot;，学不会</td><td>用更强的模型、加更多特征</td></tr><tr><td><strong>刚好</strong></td><td>好</td><td>好</td><td>泛化能力 OK</td><td>保持</td></tr><tr><td><strong>过拟合</strong></td><td>极好（~100%）</td><td>差</td><td>记住了训练集，遇到新数据就崩</td><td>加数据、加正则化、简化模型</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">PM 记忆口诀</p><p><strong>过拟合 = &quot;死记硬背&quot;，欠拟合 = &quot;啥也没学会&quot;。</strong> 产品经理不需要调参来解决，但需要能判断你的产品表现差是因为数据不够还是模型太弱——这决定了你是花钱买数据还是花钱升级模型。</p></div><hr><h2 id="三、深度学习入门" tabindex="-1">三、深度学习入门 <a class="header-anchor" href="#三、深度学习入门" aria-label="Permalink to &quot;三、深度学习入门&quot;">​</a></h2><h3 id="_3-1-神经网络是什么-五分钟理解版" tabindex="-1">3.1 神经网络是什么（五分钟理解版） <a class="header-anchor" href="#_3-1-神经网络是什么-五分钟理解版" aria-label="Permalink to &quot;3.1 神经网络是什么（五分钟理解版）&quot;">​</a></h3><p>想象一个多层的信息处理系统：</p><ul><li><strong>输入层</strong>：接收原始数据（文本→词向量、图像→像素矩阵）</li><li><strong>隐藏层</strong>：每一层提取更抽象的特征（第一层识别边缘→第二层识别形状→第三层识别物体）</li><li><strong>输出层</strong>：给出最终结果（分类概率、回归数值）</li></ul><p><strong>训练过程</strong>：前向传播（计算出预测结果）→ 计算损失（跟正确答案比较差距有多大）→ 反向传播（把误差反向传回去，调整参数）→ 重复直到收敛。</p><h3 id="_3-2-cnn-rnn-transformer-的区别" tabindex="-1">3.2 CNN / RNN / Transformer 的区别 <a class="header-anchor" href="#_3-2-cnn-rnn-transformer-的区别" aria-label="Permalink to &quot;3.2 CNN / RNN / Transformer 的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>架构</th><th>擅长处理</th><th>核心机制</th><th>产品用例</th></tr></thead><tbody><tr><td><strong>CNN</strong></td><td>图像（空间关系）</td><td>卷积核滑动提取局部特征</td><td>人脸识别、医学影像、商品图分类</td></tr><tr><td><strong>RNN / LSTM</strong></td><td>序列（时间顺序）</td><td>循环结构保留历史信息</td><td>文本生成、时间序列预测、语音识别</td></tr><tr><td><strong>Transformer</strong></td><td>任意序列（全局注意力）</td><td>Self-Attention 让每个词看到所有其他词</td><td>大语言模型、机器翻译、所有 NLP 任务</td></tr></tbody></table><p><strong>为什么 Transformer 取代了 RNN？</strong></p><p>RNN 从左到右串行处理，第 100 个词的输出依赖前面 99 个词的计算结果——不能并行，而且长距离信息会衰减。Transformer 的 Self-Attention 让每个词同时关注所有其他词，可以并行计算，而且不管多远都能直接&quot;看到&quot;。</p><div class="tip custom-block"><p class="custom-block-title">PM 理解要点</p><p>关键是&quot;注意力机制&quot;——模型不是在顺序读文本，而是像人一样&quot;看到关键信息就重点关注&quot;。比如&quot;我今天在朝阳公园旁边的星巴克喝了一杯拿铁&quot;，模型理解&quot;你在星巴克喝咖啡&quot;时，重点看&quot;星巴克&quot;和&quot;拿铁&quot;，不太关心&quot;朝阳公园&quot;。</p></div><hr><h2 id="四、大模型核心原理" tabindex="-1">四、大模型核心原理 <a class="header-anchor" href="#四、大模型核心原理" aria-label="Permalink to &quot;四、大模型核心原理&quot;">​</a></h2><h3 id="_4-1-三个核心概念" tabindex="-1">4.1 三个核心概念 <a class="header-anchor" href="#_4-1-三个核心概念" aria-label="Permalink to &quot;4.1 三个核心概念&quot;">​</a></h3><h4 id="token-最小语义单元" tabindex="-1">Token（最小语义单元） <a class="header-anchor" href="#token-最小语义单元" aria-label="Permalink to &quot;Token（最小语义单元）&quot;">​</a></h4><p>Token 不是&quot;字&quot;，是模型理解的&quot;最小单元&quot;。中文一个汉字通常是 1-2 个 Token，英文一个单词通常是 1-3 个 Token。</p><blockquote><p>比如&quot;AI 产品经理&quot;这句话，OpenAI 的分词器会把它切成 <code>[&quot;AI&quot;, &quot; 产品&quot;, &quot;经理&quot;]</code> → 3 个 Token。</p></blockquote><p><strong>PM 为什么关心 Token？</strong></p><ul><li>模型的上下文窗口有限（GPT-4o 是 128K Token）——你的输入 + 输出不能超过这个数</li><li>Token 直接等于成本——GPT-4o 每 100 万输入 Token 大概 $2.5</li><li>长文本场景需要设计&quot;分段→检索→拼接&quot;的策略</li></ul><h4 id="embedding-语义向量" tabindex="-1">Embedding（语义向量） <a class="header-anchor" href="#embedding-语义向量" aria-label="Permalink to &quot;Embedding（语义向量）&quot;">​</a></h4><p>Embedding 是把文字变成数字向量的技术。&quot;猫&quot;的向量和&quot;狗&quot;的向量在高维空间中距离很近，和&quot;汽车&quot;的向量距离很远。</p><p><strong>PM 实际应用</strong>：向量搜索（RAG）、语义相似度计算（去重/聚类）、推荐系统。</p><h4 id="attention-注意力机制" tabindex="-1">Attention（注意力机制） <a class="header-anchor" href="#attention-注意力机制" aria-label="Permalink to &quot;Attention（注意力机制）&quot;">​</a></h4><p>模型不是平等地看待输入的每个词，而是给不同位置的词分配不同的&quot;关注度&quot;。Q（Query，查询）、K（Key，键）、V（Value，值）是注意力计算的三个矩阵。</p><p><strong>PM 实际应用</strong>：理解为什么模型能&quot;读懂上下文&quot;（因为它知道每个词跟其他所有词的关系），以及为什么长文本推理对算力要求很高（注意力矩阵是 O(n²) 的复杂度）。</p><h3 id="_4-2-从-gpt-1-到-gpt-4-的演化" tabindex="-1">4.2 从 GPT-1 到 GPT-4 的演化 <a class="header-anchor" href="#_4-2-从-gpt-1-到-gpt-4-的演化" aria-label="Permalink to &quot;4.2 从 GPT-1 到 GPT-4 的演化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>版本</th><th>年份</th><th>参数量</th><th>关键突破</th><th>PM 视角</th></tr></thead><tbody><tr><td>GPT-1</td><td>2018</td><td>1.17 亿</td><td>证明预训练+微调可行</td><td>学术概念验证，没产品价值</td></tr><tr><td>GPT-2</td><td>2019</td><td>15 亿</td><td>涌现出 Zero-shot 能力</td><td>第一次看到&quot;通用语言能力&quot;</td></tr><tr><td>GPT-3</td><td>2020</td><td>1750 亿</td><td>Few-shot 学习能力惊人</td><td>API 化，催生第一批 AI 公司</td></tr><tr><td>GPT-4</td><td>2023</td><td>未公开</td><td>多模态（文本+图像输入）</td><td>推理能力接近人类专家</td></tr><tr><td>GPT-4o / 5</td><td>2024-2025</td><td>未公开</td><td>实时多模态、Agent 能力</td><td>PM 思考的是&quot;产品形态怎么重构&quot;</td></tr></tbody></table><hr><h2 id="五、mlops-——-ai-产品的-devops" tabindex="-1">五、MLOps —— AI 产品的&quot;DevOps&quot; <a class="header-anchor" href="#五、mlops-——-ai-产品的-devops" aria-label="Permalink to &quot;五、MLOps —— AI 产品的&quot;DevOps&quot;&quot;">​</a></h2><h3 id="_5-1-mlops-全景" tabindex="-1">5.1 MLOps 全景 <a class="header-anchor" href="#_5-1-mlops-全景" aria-label="Permalink to &quot;5.1 MLOps 全景&quot;">​</a></h3>',40)),(d(),s(i,null,{default:o(()=>[l(e,{id:"mermaid-578",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%E6%95%B0%E6%8D%AE%E9%87%87%E9%9B%86%5D%20--%3E%20B%5B%E6%95%B0%E6%8D%AE%E6%A0%87%E6%B3%A8%3Cbr%2F%3E%2B%E7%89%88%E6%9C%AC%E7%AE%A1%E7%90%86%5D%0A%20%20%20%20B%20--%3E%20C%5B%E6%A8%A1%E5%9E%8B%E8%AE%AD%E7%BB%83%3Cbr%2F%3E%2B%E5%AE%9E%E9%AA%8C%E8%BF%BD%E8%B8%AA%5D%0A%20%20%20%20C%20--%3E%20D%5B%E6%A8%A1%E5%9E%8B%E8%AF%84%E4%BC%B0%3Cbr%2F%3E%2B%E6%B3%A8%E5%86%8C%5D%0A%20%20%20%20D%20--%3E%20E%5B%E6%A8%A1%E5%9E%8B%E9%83%A8%E7%BD%B2%3Cbr%2F%3E%2B%E6%9C%8D%E5%8A%A1%E5%8C%96%5D%0A%20%20%20%20E%20--%3E%20F%5B%E6%A8%A1%E5%9E%8B%E7%9B%91%E6%8E%A7%3Cbr%2F%3E%2B%E5%91%8A%E8%AD%A6%5D%0A%20%20%20%20F%20--%3E%7C%E6%A3%80%E6%B5%8B%E5%88%B0%E6%BC%82%E7%A7%BB%7C%20B%0A"})]),fallback:o(()=>[...t[2]||(t[2]=[a(" Loading... ",-1)])]),_:1})),t[8]||(t[8]=n('<h3 id="_5-2-pm-视角下的-mlops-各环节" tabindex="-1">5.2 PM 视角下的 MLOps 各环节 <a class="header-anchor" href="#_5-2-pm-视角下的-mlops-各环节" aria-label="Permalink to &quot;5.2 PM 视角下的 MLOps 各环节&quot;">​</a></h3><table tabindex="0"><thead><tr><th>环节</th><th>PM 的职责</th><th>不归你管</th></tr></thead><tbody><tr><td><strong>数据采集</strong></td><td>定义数据源、数据质量标准</td><td>具体的数据抓取/存储</td></tr><tr><td><strong>数据标注</strong></td><td>设计标注规范、定义边界 Case、做一致性检验</td><td>实际执行标注</td></tr><tr><td><strong>模型训练</strong></td><td>定义评估标准、参与 Bad Case 分析</td><td>调参、代码实现</td></tr><tr><td><strong>模型评估</strong></td><td>确认评估指标是否对齐业务目标、做上线决策</td><td>跑评估脚本</td></tr><tr><td><strong>模型部署</strong></td><td>定义部署策略（灰度/A/B）、确认回滚条件</td><td>写部署脚本</td></tr><tr><td><strong>模型监控</strong></td><td>定义监控指标、确认告警阈值、触发再训练决策</td><td>搭建监控系统</td></tr></tbody></table><h3 id="_5-3-数据漂移-——-ai-pm-最该警惕的问题" tabindex="-1">5.3 数据漂移 —— AI PM 最该警惕的问题 <a class="header-anchor" href="#_5-3-数据漂移-——-ai-pm-最该警惕的问题" aria-label="Permalink to &quot;5.3 数据漂移 —— AI PM 最该警惕的问题&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">面试追问</p><p><strong>Q: 什么是数据漂移（Data Drift）？产品经理应该如何应对？</strong></p><p><strong>A:</strong> 数据漂移是指模型上线后，线上数据的统计分布和训练数据发生了偏移——比如你训练了一个用户意图分类模型，训练集里 60% 的样本是&quot;购物咨询&quot;、40% 是&quot;售后投诉&quot;。但双十一期间，&quot;售后投诉&quot;的比例暴涨到 70%——模型没见过这个分布，准确率就崩了。</p><p>产品经理应该做三件事：</p><ol><li><strong>上线前</strong>：定义漂移监控指标（特征分布 KL 散度、预测置信度分布变化）。我们项目用的是 PSI（Population Stability Index）——PSI &gt; 0.25 触发告警。</li><li><strong>发现漂移后</strong>：区分是&quot;数据漂移&quot;还是&quot;概念漂移&quot;。数据漂移（输入分布变了，但映射关系没变）一般是正常的业务波动；概念漂移（映射关系变了——比如以前说&quot;快&quot;是正面评价，现在可能是负面）需要重新标注和训练。</li><li><strong>长期机制</strong>：建立&quot;周级数据质量巡检&quot;制度——每周跑一遍线上数据的分布变化，跟训练集对比。京东金融风控产品通过这套机制把模型稳定性提升了 40%。</li></ol></div><hr><h2 id="六、面试追问合集" tabindex="-1">六、面试追问合集 <a class="header-anchor" href="#六、面试追问合集" aria-label="Permalink to &quot;六、面试追问合集&quot;">​</a></h2><h3 id="q1-如果业务方要做一个-用-ai-预测股票涨跌-的功能-作为-pm-你会怎么评估" tabindex="-1">Q1: 如果业务方要做一个&quot;用 AI 预测股票涨跌&quot;的功能，作为 PM 你会怎么评估？ <a class="header-anchor" href="#q1-如果业务方要做一个-用-ai-预测股票涨跌-的功能-作为-pm-你会怎么评估" aria-label="Permalink to &quot;Q1: 如果业务方要做一个&quot;用 AI 预测股票涨跌&quot;的功能，作为 PM 你会怎么评估？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>我会从三个层面来评估：</p><ol><li><p><strong>技术可行性</strong>：股票预测在学术界和工业界都是公认的难点——市场本身是接近有效市场的，价格已经反映了大部分公开信息。即使有 AI 模型能捕捉一些规律（比如情绪分析），超额收益也会迅速被套利行为消除。我会跟业务方说清楚：别指望能预测涨跌，但可以做&quot;基于历史数据的趋势分析&quot;和&quot;舆情情绪聚合&quot;——这个是在技术能力范围内的。</p></li><li><p><strong>合规风险</strong>：中国的《生成式 AI 服务管理办法》明确规定，提供 AI 生成的投资建议需要相关资质。没有投顾牌照，这类功能可能被监管认定为&quot;非法投资咨询&quot;。</p></li><li><p><strong>如果业务方坚持要做</strong>：我会建议把一个&quot;不可行的需求&quot;转化为两个&quot;可行的需求&quot;——做信息聚合工具（汇总市场新闻、财报数据）+ 做风险评估工具（基于历史波动率评估持仓风险），而不是直接给出买卖建议。这样既满足了用户的真实需求（想要投资决策的信息支持），又不碰技术短板和合规红线。</p></li></ol></details><h3 id="q2-面试问-解释一下-transformer-的-attention-机制-怎么回答" tabindex="-1">Q2: 面试问&quot;解释一下 Transformer 的 Attention 机制&quot;怎么回答？ <a class="header-anchor" href="#q2-面试问-解释一下-transformer-的-attention-机制-怎么回答" aria-label="Permalink to &quot;Q2: 面试问&quot;解释一下 Transformer 的 Attention 机制&quot;怎么回答？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>这个问题的面试官不会指望你推导公式，主要是看你能不能用自己的话讲清楚核心逻辑，并且能关联到产品决策。</p><p>我的回答思路是：&quot;Attention 就是给输入的每个部分一个&#39;注意力分数&#39;，让模型知道哪些部分更重要。&quot;</p><p>举个例子——输入&quot;今天在上海徐家汇的星巴克喝咖啡&quot;，当模型要理解&quot;地点&quot;的时候，它会重点看&quot;上海徐家汇星巴克&quot;这几个词，给它们的注意力分数打很高；其他词如&quot;今天&quot;&quot;喝咖啡&quot;分数就比较低。这个机制让模型能像人一样&quot;有重点地阅读&quot;，而不是逐字平等对待。</p><p>从产品角度来说，Attention 机制解释了三个关键现象：</p><ul><li>为什么大模型理解复杂上下文的成本很高——Attention 计算量和输入长度的平方成正比（O(n²)）</li><li>为什么长文本推理很慢——每个 Token 都要跟其他所有 Token 算一遍注意力</li><li>为什么 RAG 需要限制检索文档数量——拼太多的文档进去，模型注意力被稀释，反而答不准</li></ul></details><h3 id="q3-你怎么跟完全不懂-ai-的业务方解释某个模型能力边界" tabindex="-1">Q3: 你怎么跟完全不懂 AI 的业务方解释某个模型能力边界？ <a class="header-anchor" href="#q3-你怎么跟完全不懂-ai-的业务方解释某个模型能力边界" aria-label="Permalink to &quot;Q3: 你怎么跟完全不懂 AI 的业务方解释某个模型能力边界？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>我有个屡试不爽的三步法：</p><ol><li><p><strong>先给置信范围，不给绝对值</strong>：不说&quot;这个模型能做情感分析&quot;，说&quot;这个模型在大众消费品类的短评情感分析上，准确率大概 90%；但遇到电子产品长评或者讽刺性表达时，准确率会降到 70% 左右&quot;。</p></li><li><p><strong>用对比让业务方有直觉</strong>：不说&quot;F1 是 0.88&quot;，而是说&quot;100 条负评里，模型能抓出 95 条，但会漏掉 5 条——这 5 条漏掉的你受得了吗？另外，模型会把 8 条好评判成负评——这 8 个被冤枉的用户你要怎么处理？&quot;</p></li><li><p><strong>给替代方案，不留死角</strong>：补一句&quot;对于高风险的场景（比如涉及赔偿的投诉），我们设计人工复核通道——模型先筛一遍，置信度低于 80% 的转人工。这样兼顾效率和准确。&quot;</p></li></ol><p>关键是<strong>不要用术语糊弄人，也不要用&quot;反正 AI 能搞定&quot;这种回答模糊过去</strong>。说出不完美就是专业，拍胸脯保证才是外行。</p></details><h3 id="q4-token-计费模式对产品设计有什么影响" tabindex="-1">Q4: Token 计费模式对产品设计有什么影响？ <a class="header-anchor" href="#q4-token-计费模式对产品设计有什么影响" aria-label="Permalink to &quot;Q4: Token 计费模式对产品设计有什么影响？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>影响非常大，直接决定了产品形态和商业模式。说几个实际案例：</p><p><strong>场景一：客服 Bot</strong>。如果每次对话都在 System Prompt 里拼大段产品手册（3000 Token）+ 检索到的相关文档（2000 Token）+ 对话历史（1000 Token），光输入就 6000 Token。GPT-4o 按 $2.5/百万 Token 算，单次对话 API 成本约 $0.015，大概 1 毛钱人民币。一天 5000 次咨询就是 500 块，一个月 15000。如果换成 GPT-4o-mini（价格是 1/10），同样场景成本降到 1500/月。但准确率可能从 92% 降到 87%——你得权衡省的钱和丢的体验。</p><p><strong>场景二：文档分析工具</strong>。用户上传一个 100 页的 PDF，如果你把全文 Token 化之后全塞给模型，光这一轮就可能吃掉几万个 Token。你必须在产品设计中加入&quot;检索+分段&quot;策略——先定位相关段落，再送模型分析——而不是把全文喂进去。这是成本倒逼的产品设计决策。</p><p><strong>场景三：定价策略</strong>。如果你的产品成本全靠 API，你的定价必须考虑 Token 成本弹性。按次收费的固定定价非常危险——用户可能发一段 10 Token 的查询（成本很低），也可能一句&quot;把这份 500 页的合同帮我过一遍&quot;吃掉 5 万 Token。所以大多数 AI 产品都是&quot;分层+限额&quot;定价——免费版每天 100 次、Pro 版不限额但要付月费。</p></details><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./role-overview">AI PM 角色定位与三大方向</a></li><li><a href="./prompt-engineering">Prompt 工程</a></li><li><a href="./large-model">大模型技术栈与 Agent 设计</a></li><li><a href="./interview">AI PM 面试高频题</a></li></ul>',17))])}const P=E(h,[["render",q]]);export{k as __pageData,P as default};
